def topological_waves(tasks: list[Task]) -> list[list[str]]:
    """Return tasks grouped into execution waves.

    Wave 0 has no dependencies; wave N depends only on tasks in waves 0..N-1.
    All tasks in the same wave can run in parallel.
    """
    index  = {t.id: t for t in tasks}
    in_deg = {t.id: len(t.depends_on) for t in tasks}
    graph  = {t.id: [] for t in tasks}  # id -> list of ids that depend on it
    for t in tasks:
        for dep in t.depends_on:
            graph[dep].append(t.id)

    waves, done = [], set()
    while len(done) < len(tasks):
        wave = [tid for tid, deg in in_deg.items() if deg == 0 and tid not in done]
        if not wave:
            raise ValueError("Cycle detected in task dependencies")
        waves.append(wave)
        done.update(wave)
        for tid in wave:
            for successor in graph[tid]:
                in_deg[successor] -= 1
    return waves

# Example output for TASKS above:
# Wave 0: ["T1"]              <- entry node, runs alone
# Wave 1: ["T2", "T3"]        <- both depend only on T1, run in parallel
# Wave 2: ["T4", "T5"]        <- T4 needs T2, T5 needs T2+T3
# Wave 3: ["T6"]              <- needs T4+T5
# Wave 4: ["T7"]              <- needs T6

def detect_cycles(tasks: list[Task]) -> list[list[str]]:
    """Return a list of cycles found in the dependency graph.

    Each cycle is reported as the ordered list of task IDs forming it.
    Returns an empty list when the graph is acyclic.
    """
    WHITE, GRAY, BLACK = 0, 1, 2
    color = {t.id: WHITE for t in tasks}
    index = {t.id: t for t in tasks}
    cycles: list[list[str]] = []

    def dfs(node: str, path: list[str]):
        color[node] = GRAY
        path.append(node)
        for dep in index[node].depends_on:
            if color[dep] == GRAY:
                start = path.index(dep)
                cycles.append(path[start:] + [dep])  # record cycle
            elif color[dep] == WHITE:
                dfs(dep, path)
        path.pop()
        color[node] = BLACK

    for t in tasks:
        if color[t.id] == WHITE:
            dfs(t.id, [])
    return cycles

CYCLE_REPAIR_PROMPT = """
The following tasks form a dependency cycle, which prevents execution:
{cycle}

Describe which dependency should be removed to break the cycle,
and confirm the task list still makes logical sense.
Return JSON: {{"remove": {{"from": "<id>", "dep": "<id>"}}, "rationale": "..."}}
"""

def repair_cycle(cycle: list[str], tasks: list[Task]) -> None:
    """Ask the LLM which edge to drop, then mutate the task list."""
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[{"role": "user", "content":
            CYCLE_REPAIR_PROMPT.format(cycle=" -> ".join(cycle))}],
    )
    fix = json.loads(response.content[0].text)
    task = next(t for t in tasks if t.id == fix["remove"]["from"])
    task.depends_on.remove(fix["remove"]["dep"])
    print(f"Removed {fix['remove']['dep']} from {task.id}: {fix['rationale']}")
